/**
 * Load Google Ads event listeners
 * */

// view_item_list event
jQuery(document).on("pmw:pixel:view-item-list", (event, payload) => {

	try {
		if (!pmw.shouldFireBrowserPixel(payload, "google_ads")) return;

		// Get Google Ads data from the unified payload structure
		const googleAdsData = payload.pixels?.google_ads;

		if (!googleAdsData) {
			return;
		}

		pmw.gtagLoaded().then(() => {
			gtag("event", "view_item_list", googleAdsData);
			pmw.console.log("Google Ads: view_item_list event sent", googleAdsData);
		});
	} catch (e) {
		console.error(e);
	}
});

