// user log in event
jQuery(document).on("pmw:pixel:login", () => {

	try {
		if (jQuery.isEmptyObject(pmwDataLayer?.pixels?.google?.ads?.conversion_ids)) return;
		if (!pmw.googleConfigConditionsMet({type: "marketing"})) return;

		let data = {
			send_to: pmw.getGoogleAdsConversionIdentifiers(),
		};

		if (pmwDataLayer?.user?.id?.raw) {
			data.user_id = pmwDataLayer.user.id.raw;
		}

		pmw.gtagLoaded().then(() => {
			gtag("event", "login", data);
			pmw.console.log("Google Ads: login event sent", data);
		});
	} catch (e) {
		console.error(e);
	}
});

/**
 * Google Ads remarketing purchase
 *
 * https://support.google.com/google-ads/answer/7305793
 */
jQuery(document).on("pmw:pixel:purchase", () => {

	try {
		if (jQuery.isEmptyObject(pmw.getGoogleAdsConversionIdentifiersWithLabel())) return;
		if (!pmw.googleConfigConditionsMet({type: "marketing"})) return;

		let data = {
			send_to: pmw.getGoogleAdsConversionIdentifiers(),
			value  : pmwDataLayer.order.value.marketing,
			// currency: pmwDataLayer.order.currency,
			items: pmw.getGoogleAdsRegularOrderItems(),
		};

		pmw.gtagLoaded().then(() => {
			gtag("event", "purchase", data);
			pmw.console.log("Google Ads: purchase event sent (for remarketing lists)", data);
		});

	} catch (e) {
		console.error(e);
	}
});

/**
 * Google Ads conversion event
 *
 * new_customer parameter: https://support.google.com/google-ads/answer/9917012
 * cart data: https://support.google.com/google-ads/answer/9028614
 * customer_lifetime_value is undocumented, but available in gtag.js
 */
jQuery(document).on("pmw:pixel:purchase", () => {

	try {
		if (jQuery.isEmptyObject(pmw.getGoogleAdsConversionIdentifiersWithLabel())) return;
		if (!pmw.googleConfigConditionsMet({type: "marketing"})) return;

		let data = {
			send_to       : pmw.getGoogleAdsConversionIdentifiersWithLabel(),
			transaction_id: pmwDataLayer.order.number,
			value         : pmwDataLayer.order.value.marketing,
			currency      : pmwDataLayer.order.currency,
			new_customer  : pmwDataLayer.order.new_customer,
		};

		if (pmwDataLayer?.order?.value?.ltv?.marketing) {
			data.customer_lifetime_value = pmwDataLayer.order.value.ltv.marketing;
		}

		if (pmwDataLayer?.user?.id?.raw) {
			data.user_id = pmwDataLayer.user.id.raw;
		}

		// https://support.google.com/google-ads/answer/9028614
		if (pmwDataLayer?.order?.aw_merchant_id) {
			data.discount         = pmwDataLayer.order.discount;
			data.aw_merchant_id   = pmwDataLayer.order.aw_merchant_id;
			data.aw_feed_country  = pmwDataLayer.order.aw_feed_country;
			data.aw_feed_language = pmwDataLayer.order.aw_feed_language;
			data.items            = pmw.getGoogleAdsRegularOrderItems();
		}

		// Add custom variables
		if (pmwDataLayer?.order?.google?.ads?.custom_variables) {
			Object.entries(pmwDataLayer.order.google.ads.custom_variables).forEach(([key, value]) => {
				data[key] = value;
			});
		}

		pmw.gtagLoaded().then(() => {
			// Event needs to be "purchase" (not "conversion") in order to be able to track cart data:
			// https://support.google.com/google-ads/answer/9028614
			gtag("event", "purchase", data);
			pmw.console.log("Google Ads: conversion event sent", data);
		});

	} catch (e) {
		console.error(e);
	}
});
